```aether:src/utils/validation.ts
export const isValidEmail = (email: string): boolean => {
  // A simple regex for email validation. More robust validation might be needed for production.
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
};

export const isValidPassword = (password: string): boolean => {
  // Example: Password must be at least 8 characters long, contain a number and a special character.
  // For this exercise, let's keep it simple: at least 8 characters.
  return password.length >= 8;
};
