import { Hono } from 'hono';
import authRoutes from './routes/auth';

const app = new Hono();

// Mount authentication routes
app.route('/auth', authRoutes);

// Basic root route
app.get('/', (c) => {
  return c.text('Welcome to the User Registration API!');
});

// Error handling for unmatched routes
app.notFound((c) => {
  return c.json({ message: 'Not Found' }, 404);
});

// Global error handler
app.onError((err, c) => {
  console.error(`${err}`);
  return c.json({ error: 'An unexpected error occurred.' }, 500);
});

// Export the Hono app for serverless environments or direct Node.js server setup
export default app;

// For local development, you might want to run it directly
// This part is typically handled by a separate server file or build process in production.
// For this exercise, we'll include a simple listener.
if (process.env.NODE_ENV !== 'test') {
  const port = parseInt(process.env.PORT || '3000');
  console.log(`Server is running on http://localhost:${port}`);
  // Hono's app.listen is for Node.js environments
  // In a real project, you might use `serve` from 'bun' or 'deno' or a Node.js http server.
  // For Hono on Node.js, you'd typically use a server adapter like `@hono/node-server`.
  // For simplicity, we'll just export the app and assume a runner will pick it up.
  // If running directly with `node src/index.ts`, you'd need a server adapter:
  // import { serve } from '@hono/node-server';
  // serve({
  //   fetch: app.fetch,
  //   port
  // });
}
